mapper.sql:
AND AA.DEL_YN = 'N'	
/* 사용자는 무조건 삭제된 게시물 못보게 함*/


	AND AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR}



	AND UPPER(AA.TITLE) LIKE UPPER('%' || #{titleL, jdbcType=VARCHAR} || '%')



	AND AA.CATE_CD = #{cateCd, jdbcType=VARCHAR}





			/* 공지글 */
			AND AA.FIX_YN = 'Y'
			AND NOW()::DATE BETWEEN 
				COALESCE(NULLIF(TRIM(AA.FROM_DATE), ''), '2000-01-01')::DATE AND 
				COALESCE(NULLIF(TRIM(AA.TO_DATE)	, ''), '3000-12-31')::DATE


			AND AA.FIX_YN = 'N'

mapper.select:
/* com.erns.coching.board.mapper.BoardDAO.getList */
SELECT ZZ.* FROM ( SELECT
, MEMB.MEMB_NAME AS REG_NAME , COALESCE( (SELECT COUNT(*) FROM T_BOARD_CMT BC WHERE AA.BOARD_SEQ = BC.BOARD_SEQ AND BC.DEL_YN = 'N') , 0 ) AS CMT_CNT /* 코멘트 갯수 */ FROM T_BOARD_INF AA LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ
ORDER BY AA.BOARD_SEQ DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.board.mapper.BoardDAO.load */

SELECT

	, AA.CONTENT
FROM T_BOARD_INF AA			

	AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.loadDetail */

SELECT

	, AA.CONTENT
	, BB.BOARD_NAME
	, MEMB.MEMB_NAME AS REG_NAME
	, (SELECT COUNT(*) 
		 FROM T_BOARD_CMT 
		 WHERE BOARD_SEQ = #{boardSeq, jdbcType=INTEGER} 
		 AND DEL_YN = 'N'
		) AS CMT_CNT
	, (
			SELECT MIN(AA.BOARD_SEQ)
			FROM T_BOARD_INF AA
			WHERE AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR}
				AND AA.BOARD_SEQ > #{boardSeq, jdbcType=INTEGER}
				AND AA.DEL_YN = 'N'
		) AS NEXT
	, (	
			SELECT MAX(AA.BOARD_SEQ)
			FROM T_BOARD_INF AA
			WHERE  AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR} 
				AND AA.BOARD_SEQ < #{boardSeq, jdbcType=INTEGER}
				AND AA.DEL_YN = 'N'
		) AS PREV
	, CC.CMT_USE_YN
FROM T_BOARD_INF AA
	LEFT JOIN T_BOARD_MST BB	ON AA.BOARD_MST_ID = BB.BOARD_MST_ID
	LEFT JOIN T_MEMB_INF MEMB	ON AA.RGTR = MEMB.MEMB_SEQ
	LEFT JOIN T_BOARD_OPT CC	ON AA.BOARD_MST_ID = CC.BOARD_MST_ID

	AND AA.BOARD_MST_ID = #{boardMstId, jdbcType=VARCHAR} 
	AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

mapper.insert:
/* com.erns.coching.board.mapper.BoardDAO.insert */


	SELECT nextval('seq_t_board_inf')


INSERT INTO T_BOARD_INF (
		BOARD_SEQ
	, BOARD_MST_ID
	, CATE_CD
	, TITLE
	, CONTENT
	, WRITER
	, SORT_ORD
	, DEL_YN
	, VIEWS
	, FROM_DATE
	, TO_DATE
	, FIX_YN

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
		#{boardSeq		, jdbcType=INTEGER}
	, #{boardMstId	, jdbcType=VARCHAR}
	, #{cateCd			, jdbcType=VARCHAR}
	, #{title				, jdbcType=VARCHAR}
	, #{content			, jdbcType=VARCHAR}
	, #{writer			, jdbcType=VARCHAR}
	, #{sortOrd			, jdbcType=INTEGER}
	, COALESCE(#{delYn	, jdbcType=CHAR}, 'N')
	, COALESCE(#{views	, jdbcType=INTEGER}, 0)
	, #{fromDate		, jdbcType=VARCHAR}
	, #{toDate			, jdbcType=VARCHAR}
	, COALESCE(#{fixYn	, jdbcType=CHAR}, 'N')

	, #{rgtr		, jdbcType=INTEGER}
	, now()
	, #{chnr		, jdbcType=INTEGER}
	, now()
)

mapper.update:
/* com.erns.coching.board.mapper.BoardDAO.update */

UPDATE T_BOARD_INF SET
		CATE_CD       = #{cateCd		, jdbcType=VARCHAR}
	, TITLE         = #{title		, jdbcType=VARCHAR}
	, CONTENT       = #{content		, jdbcType=VARCHAR}
	, WRITER        = #{writer		, jdbcType=VARCHAR}

	, CHNR 					= #{chnr		, jdbcType=INTEGER}
	, CHNG_DTTM			= now()

	AND BOARD_SEQ 	= #{boardSeq	, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.updateViewCnt */

UPDATE T_BOARD_INF SET
	VIEWS 		= VIEWS + 1

	AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

		/* com.erns.coching.board.mapper.BoardDAO.updateDelYn */

		UPDATE T_BOARD_INF SET
    	  DEL_YN 			= #{delYn	, jdbcType=CHAR}
			, CHNR 				= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM		= now()

			AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.board.mapper.BoardDAO.delete */

DELETE FROM T_BOARD_INF

	AND BOARD_SEQ 	= #{boardSeq, jdbcType=INTEGER}
